+/**
+ * Helper to create MCP tool result
+ */
+function createResult(data: unknown, isError = false): MCPToolResult {
+  return {
+    content: [
+      {
+        type: 'text',
+        text: typeof data === 'string' ? data : JSON.stringify(data, null, 2),
+      },
+    ],
+    isError,
+  };
